import "./index.css";
import usefetch from './fetchdata.js'; // your custom hook
import { Link } from "react-router-dom";
import Yello from "./Yettostart.js";

const Homepage = () => {
  const { Data, Ispending , Iserror} = usefetch('')

  return (
    <div className="homepage">
        {Ispending && <div>Loading</div>}
        {Iserror && <div> Getting a error fecthing the data</div>}
      {/* To Do Tasks */}
      <div className="yts">
        {Data && <Yello indata = {Data} />}
      </div>

      {/* <div className="inprogress">
        <h5>In Progress</h5>
